  "HERO-SPEECHES": {
   "name": "HERO-SPEECHES",
   "kind": "global",
   "file": "hero.zil",
   "line": 852,
   "value": "<TABLE \"\"I haven't found your father. We've long suspected a passage\nunder the library, but I cannot find an entrance,\" says Jamison\" \"\"If there is any trouble, and I am unable to help -- a signal from\nan upstairs seaward window will bring my men. They can be here in moments,\"\nthe Captain says\" \"\"I wish you would call me 'Nicholas' -- I feel I know you much\nbetter than our brief acquaintance would allow.\" He presses your hand\">"
  },
